"use server";

export type UpdateProfileResult = { success: true } | { success: false; code: ErrorCode };

export async function editProfile(nickname: string, introduce: string): Promise<UpdateProfileResult> {
  const supabase = await createClient();
  const { data: { session } } = await supabase.auth.getSession();

  if (!session) return { success: false, code: "UNAUTHORIZED" };

  const response = await fetch(
    `${process.env.API_URL}/v1/users/${session.user.id}`,
    {
      method: "PATCH",
      headers: {
        Authorization: `Bearer ${session.access_token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ nickname, introduce }),
    }
  );

  if (!response.ok) return { success: false, code: "UPDATE_FAILED" };
  return { success: true };
}
```

