"use client";

import {
  type JSX,
  type PropsWithChildren,
  createContext,
  useContext,
  useState,
  useTransition,
} from "react";
import { Button } from "@/components/ui/button";
import { useIsHydrated } from "@/hooks/use-is-hydrated";
import {
  type GenerateApiKeyErrorCode,
  generateApiKey,
} from "./generate-api-key.action";

const errorMessages: Record<GenerateApiKeyErrorCode, string> = {
  UNAUTHORIZED: "認証が切れています。再度ログインしてください。",
  APIKEY_QUOTA_EXCEEDS_LIMIT:
    "API キーの登録上限に達しています。不要なキーを削除してから再度生成してください。",
  APIKEY_LOCK_TIMEOUT:
    "API キーを生成できませんでした。時間をおいて再度お試しください。",
  INTERNAL_ERROR:
    "予期しないエラーが発生しました。時間をおいて再度お試しください。",
};

type CopyState = "idle" | "copied" | "failed";

interface GenerateApiKeyContextValue {
  isHydrated: boolean;
  isPending: boolean;
  generated: string | null;
  errorCode: GenerateApiKeyErrorCode | null;
  copyState: CopyState;
  handleGenerate: () => void;
  handleCopy: () => Promise<void>;
  handleClose: () => void;
}

const GenerateApiKeyContext = createContext<GenerateApiKeyContextValue | null>(
  null,
);

function useGenerateApiKeyContext(): GenerateApiKeyContextValue {
  const ctx = useContext(GenerateApiKeyContext);
  if (ctx === null) {
    throw new Error(
      "GenerateApiKey コンポーネントは GenerateApiKeyProvider 配下で使用してください",
    );
  }
  return ctx;
}

export function GenerateApiKeyProvider({
  children,
}: PropsWithChildren): JSX.Element {
  const isHydrated = useIsHydrated();
  const [isPending, startTransition] = useTransition();
  const [generated, setGenerated] = useState<string | null>(null);
  const [errorCode, setErrorCode] = useState<GenerateApiKeyErrorCode | null>(
    null,
  );
  const [copyState, setCopyState] = useState<CopyState>("idle");

  const handleGenerate = (): void => {
    setErrorCode(null);
    setCopyState("idle");
    startTransition(async () => {
      const result = await generateApiKey();
      if (result.success) {
        setGenerated(result.apiKey);
      } else {
        setGenerated(null);
        setErrorCode(result.code);
      }
    });
  };

  const handleCopy = async (): Promise<void> => {
    if (generated === null) return;
    try {
      await navigator.clipboard.writeText(generated);
      setCopyState("copied");
    } catch {
      setCopyState("failed");
    }
  };

  const handleClose = (): void => {
    setGenerated(null);
    setCopyState("idle");
  };

  return (
    <GenerateApiKeyContext.Provider
      value={{
        isHydrated,
        isPending,
        generated,
        errorCode,
        copyState,
        handleGenerate,
        handleCopy,
        handleClose,
      }}
    >
      {children}
    </GenerateApiKeyContext.Provider>
  );
}

export function GenerateApiKeyTrigger(): JSX.Element {
  const { isHydrated, isPending, handleGenerate } = useGenerateApiKeyContext();
  return (
    <Button
      type="button"
      onClick={handleGenerate}
      size="sm"
      disabled={!isHydrated || isPending}
    >
      {isPending ? "生成中..." : "API キー生成"}
    </Button>
  );
}

export function GenerateApiKeyResult(): JSX.Element | null {
  const { generated, errorCode, copyState, handleCopy, handleClose } =
    useGenerateApiKeyContext();

  if (generated === null && errorCode === null) {
    return null;
  }

  return (
    <div className="flex flex-col gap-4">
      {errorCode !== null && (
        <p
          role="alert"
          className="border-destructive bg-destructive/10 text-destructive border px-4 py-3 text-sm"
        >
          {errorMessages[errorCode]}
        </p>
      )}

      {generated !== null && (
        <div className="border-primary bg-card flex flex-col gap-3 border px-4 py-4">
          <p className="text-sm">
            API
            キーを生成しました。この画面を閉じると再表示できないため、必ずコピーして安全な場所に保管してください。
          </p>
          <code className="bg-muted block px-3 py-2 font-mono text-sm break-all">
            {generated}
          </code>
          <div className="flex items-center gap-3">
            <Button
              type="button"
              variant="secondary"
              onClick={handleCopy}
              size="sm"
            >
              コピー
            </Button>
            <Button
              type="button"
              variant="outline"
              onClick={handleClose}
              size="sm"
            >
              閉じる
            </Button>
            {copyState === "copied" && (
              <span
                aria-live="polite"
                className="text-muted-foreground text-sm"
              >
                コピーしました
              </span>
            )}
            {copyState === "failed" && (
              <span aria-live="polite" className="text-destructive text-sm">
                コピーに失敗しました
              </span>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

