          </code>
          <div className="flex items-center gap-3">
            <Button
              type="button"
              variant="secondary"
              onClick={handleCopy}
              size="sm"
            >
              コピー
            </Button>
            <Button
              type="button"
              variant="outline"
              onClick={handleClose}
